fn resolved_failure_outlives_same_session_modified_spam() {
    let s = store();
    let stable_created = NOW - 10 * 24 * HOUR;
    s.upsert_node(&Node::new(
        "artifact:stable",
        NodeType::Artifact,
        "stable",
        stable_created,
    ))
    .unwrap();
    add_node(&s, "artifact:consumer", NodeType::Artifact, "consumer", NOW);
    add_node(&s, "artifact:spam", NodeType::Artifact, "spam", NOW);

    let failure = Node::new("execution:failure", NodeType::Execution, "cargo test", NOW)
        .with_content("exit=1\n");
    let success = Node::new(
        "execution:success",
        NodeType::Execution,
        "cargo test",
        NOW + 2 * HOUR,
    )
    .with_content("exit=0\n");
    let spam =
        Node::new("execution:spam", NodeType::Execution, "green", NOW).with_content("exit=0\n");
    let commit = Node::new("intent:commit", NodeType::Intent, "fix stable", NOW + HOUR);
    let decision = Node::new(
        "intent:decision",
        NodeType::Intent,
        "DECISION: preserve stable",
        NOW + HOUR,
    );
    for node in [failure, success, spam, commit, decision] {
        s.upsert_node(&node).unwrap();
    }

    let failed_on = raw_edge(
        "execution:failure",
        "artifact:stable",
        RelationType::FailedOn,
        1.0,
        24.0,
        NOW,
    );
    s.upsert_edge(&failed_on).unwrap();
    s.upsert_edge(&raw_edge(
        "intent:commit",
        "artifact:stable",
        RelationType::Refactored,
        1.0,
        168.0,
        NOW + HOUR,
    ))
    .unwrap();
    s.upsert_edge(&raw_edge(
        "artifact:consumer",
        "artifact:stable",
        RelationType::Imports,
        1.0,
        168.0,
        NOW,
    ))
    .unwrap();
    s.upsert_edge(&raw_edge(
        "intent:decision",
        "artifact:stable",
        RelationType::RelatesTo,
        1.0,
        48.0,
        NOW + HOUR,
    ))
    .unwrap();
    for _ in 0..400 {
        s.upsert_edge(&raw_edge(
            "execution:spam",
            "artifact:spam",
            RelationType::Modified,
            1.0,
            24.0,
            NOW,
        ))
        .unwrap();
    }

    let evidence = s.signal_evidence(&failed_on, NOW + 6 * 24 * HOUR).unwrap();
    assert!(evidence.consequence);
    assert!(evidence.surprise);
    assert!(evidence.source_diversity >= 3);
    assert!(evidence.deliberate_attention);

    let failure_graph = s
        .traverse(
            &["artifact:stable".into()],
            Direction::Incoming,
            1,
            PRUNE_THRESHOLD,
            NOW + 6 * 24 * HOUR,
        )
        .unwrap();
    assert!(failure_graph
        .edges
        .iter()
        .any(|edge| edge.relation == RelationType::FailedOn));
    let spam_graph = s
        .traverse(
            &["artifact:spam".into()],
            Direction::Incoming,
            1,
            PRUNE_THRESHOLD,
            NOW + 6 * 24 * HOUR,
        )
        .unwrap();
    assert!(spam_graph.edges.is_empty());
}

#[test]
fn near_expiry_proven_signal_is_routed_to_consolidation() {
    let s = store();
    let target = Node::new(
        "artifact:stable",
        NodeType::Artifact,
        "stable",
        NOW - 10 * 24 * HOUR,
    );
    let failure = Node::new("execution:failure", NodeType::Execution, "cargo test", NOW)
        .with_content("exit=1\n");
    let success = Node::new(
        "execution:success",
        NodeType::Execution,
        "cargo test",
        NOW + 2 * HOUR,
    )
    .with_content("exit=0\n");
    let commit = Node::new("intent:commit", NodeType::Intent, "fix", NOW + HOUR);
    for node in [target, failure, success, commit] {
        s.upsert_node(&node).unwrap();
    }
    let failed_on = raw_edge(
        "execution:failure",
        "artifact:stable",
        RelationType::FailedOn,
        1.0,
        24.0,
        NOW,
    );
    s.upsert_edge(&failed_on).unwrap();
    s.upsert_edge(&raw_edge(
        "intent:commit",
        "artifact:stable",
        RelationType::Refactored,
        1.0,
        168.0,
        NOW + HOUR,
    ))
    .unwrap();

    let candidates = s.expiring_signal_candidates(NOW + 20 * 24 * HOUR).unwrap();
    assert!(candidates
        .iter()
        .any(|candidate| candidate.relation == RelationType::FailedOn));

    let early = NOW + 24 * HOUR;
    let s = s.with_decay_policy(policy(&[], 0.5));
    assert!(s
        .expiring_signal_candidates(early)
        .unwrap()
        .iter()
        .any(|candidate| candidate.relation == RelationType::FailedOn));
    let s = s.with_decay_policy(policy(&[], 0.001));
    assert!(s.expiring_signal_candidates(early).unwrap().is_empty());

    let s = s.with_decay_policy(policy(&[(RelationType::FailedOn, 8_760.0)], 0.05));
    assert!(s
        .expiring_signal_candidates(NOW + 20 * 24 * HOUR)
        .unwrap()
        .is_empty());
}

#[test]
fn promotion_candidates_group_corroborating_signal_by_subject() {
    // ADR-0022: expiring proven-signal edges that share a target collapse into one
    // promotion candidate whose evidence is the distinct corroborating source nodes
    // plus the target — the shape the Intent plane's gated promoter consumes.
    let s = store();
    s.upsert_node(&Node::new(
        "artifact:stable",
        NodeType::Artifact,
        "stable",
        NOW - 10 * 24 * HOUR,
    ))
    .unwrap();
    // Three distinct failing executions on the same target...
    for i in 1..=3i64 {
        let id = format!("execution:failure{i}");
        s.upsert_node(
            &Node::new(&id, NodeType::Execution, "cargo test", NOW + i * HOUR)
                .with_content("exit=1\n"),
        )
        .unwrap();
        s.upsert_edge(&raw_edge(
            &id,
            "artifact:stable",
            RelationType::FailedOn,
            1.0,
            24.0,
            NOW + i * HOUR,
        ))
        .unwrap();
    }
    // ...later resolved (a success plus a refactor commit) so each failure edge is a
    // consequence and earns signal_multiplier > 1.
    s.upsert_node(
        &Node::new(
            "execution:success",
            NodeType::Execution,
            "cargo test",
            NOW + 5 * HOUR,
        )
        .with_content("exit=0\n"),
    )
    .unwrap();
    s.upsert_node(&Node::new(
        "intent:commit",
        NodeType::Intent,
        "fix stable",
        NOW + 5 * HOUR,
    ))
    .unwrap();
    s.upsert_edge(&raw_edge(
        "intent:commit",
        "artifact:stable",
        RelationType::Refactored,
        1.0,
        168.0,
        NOW + 5 * HOUR,
    ))
    .unwrap();

    let horizon = NOW + 20 * 24 * HOUR;
    // Sanity: the three failures are near-expiry proven signal.
    let failing_sources: std::collections::BTreeSet<_> = s
        .expiring_signal_candidates(horizon)
        .unwrap()
        .into_iter()
        .filter(|c| c.relation == RelationType::FailedOn && c.target_id == "artifact:stable")
        .map(|c| c.source_id)
        .collect();
    assert!(
        failing_sources.len() >= 3,
        "expected 3 corroborating failures, got {failing_sources:?}"
    );

    // The promotion pass collapses them into one subject-level candidate.
    let candidates = s.promotion_candidates(horizon).unwrap();
    let grouped = candidates
        .iter()
        .find(|c| {
            c.subject == "artifact:stable"
                && c.evidence_node_ids
                    .iter()
                    .filter(|id| id.starts_with("execution:failure"))
                    .count()
                    >= 3
        })
        .expect("a grouped failed_on promotion candidate");
    assert!(grouped
        .evidence_node_ids
        .contains(&"artifact:stable".to_string()));
    assert!(grouped.last_seen >= grouped.first_seen);
}

#[test]
fn expired_proven_signal_waits_for_consolidation_acknowledgement() {
    let s = store();
    s.upsert_node(&Node::new(
        "artifact:stable",
        NodeType::Artifact,
        "stable",
        NOW - 10 * 24 * HOUR,
    ))
    .unwrap();
    for node in [
        Node::new("execution:failure", NodeType::Execution, "cargo test", NOW)
            .with_content("exit=1\n"),
        Node::new(
            "execution:success",
            NodeType::Execution,
            "cargo test",
            NOW + 2 * HOUR,
        )
        .with_content("exit=0\n"),
        Node::new("intent:commit", NodeType::Intent, "fix stable", NOW + HOUR),
    ] {
        s.upsert_node(&node).unwrap();
    }
    s.upsert_edge(&raw_edge(
        "execution:failure",
        "artifact:stable",
        RelationType::FailedOn,
        1.0,
        24.0,
        NOW,
    ))
    .unwrap();
    s.upsert_edge(&raw_edge(
        "intent:commit",
        "artifact:stable",
        RelationType::Refactored,
        1.0,
        168.0,
        NOW + HOUR,
    ))
    .unwrap();

    let outcome = s.prune_with_signal(NOW + 60 * 24 * HOUR).unwrap();
    assert!(outcome
        .signal_candidates
        .iter()
        .any(|candidate| candidate.relation == RelationType::FailedOn));
    assert!(s.get_node("execution:failure").unwrap().is_some());

    let owner = acquire_lease(&s, NOW + 60 * 24 * HOUR);
    s.commit_signal_consolidation(
        &owner,
        NOW + 60 * 24 * HOUR,
        &outcome.signal_candidates,
        &[],
        &[],
    )
    .unwrap();
    assert!(s.get_node("execution:failure").unwrap().is_none());
}

#[test]
fn signal_consolidation_commits_facts_and_acknowledgement_atomically() {
    let s = store();
    add_node(&s, "execution:failure", NodeType::Execution, "failure", NOW);
    add_node(&s, "artifact:target", NodeType::Artifact, "target", NOW);
    s.upsert_edge(&raw_edge(
        "execution:failure",
        "artifact:target",
        RelationType::FailedOn,
        1.0,
        24.0,
        NOW,
    ))
    .unwrap();
    let candidate = SignalCandidate {
        source_id: "execution:failure".to_string(),
        target_id: "artifact:target".to_string(),
        relation: RelationType::FailedOn,
        effective: 0.01,
        signal_multiplier: 2.0,
        evidence: SignalEvidence {
            reinforcement_count: 1,
            ..SignalEvidence::default()
        },
        updated_at: NOW,
    };
    let intent = Node::new("intent:gist", NodeType::Intent, "gist", NOW);
    let link = Edge::new(
        "intent:gist",
        "artifact:target",
        RelationType::RelatesTo,
        NOW,
    );

    let owner = acquire_lease(&s, NOW);
    let (outcome, edges_removed, nodes_removed) = s
        .commit_signal_consolidation(&owner, NOW, &[candidate], &[intent], &[link])
        .unwrap();

    assert_eq!(outcome.nodes_created, 1);
    assert_eq!(outcome.edges_created, 1);
    assert_eq!(edges_removed, 1);
    assert_eq!(nodes_removed, 1);
    assert!(s.get_node("intent:gist").unwrap().is_some());
    assert!(s.get_node("execution:failure").unwrap().is_none());
}

